/employees POST.raw_response:
{
  "positive": [
    {
      "name": "Create new employee with valid data",
      "method": "POST",
      "path": "/employees",
      "payload": {"firstName": "John", "lastName": "Doe", "email": "john.doe@example.com", "jobTitle": "Software Engineer"},
      "expected_status": 201,
      "description": "Create a new employee with valid data",
      "context_capture": {"enabled": true, "fields": ["id", "firstName", "lastName"], "store_as": "employee"}
    },
    {
      "name": "Create new employee with valid data and address",
      "method": "POST",
      "path": "/employees",
      "payload": {"firstName": "Jane", "lastName": "Smith", "email": "jane.smith@example.com", "jobTitle": "Marketing Manager", "address": {"street": "123 Main St", "city": "Anytown", "state": "CA", "zip": "12345"}},
      "expected_status": 201,
      "description": "Create a new employee with valid data and address",
      "context_capture": {"enabled": true, "fields": ["id", "firstName", "lastName"], "store_as": "employee"}
    },
    {
      "name": "Create new employee with valid data and phone number",
      "method": "POST",
      "path": "/employees",
      "payload": {"firstName": "Bob", "lastName": "Johnson", "email": "bob.johnson@example.com", "jobTitle": "Sales Representative", "phone": "123-456-7890"},
      "expected_status": 201,
      "description": "Create a new employee with valid data and phone number",
      "context_capture": {"enabled": true, "fields": ["id", "firstName", "lastName"], "store_as": "employee"}
    }
  ],
  "negative": [
    {
      "name": "Create new employee with missing first name",
      "method": "POST",
      "path": "/employees",
      "payload": {"lastName": "Doe", "email": "john.doe@example.com", "jobTitle": "Software Engineer"},
      "expected_status": 400,
      "description": "Create a new employee with missing first name"
    },
    {
      "name": "Create new employee with invalid email",
      "method": "POST",
      "path": "/employees",
      "payload": {"firstName": "John", "lastName": "Doe", "email": "invalid_email", "jobTitle": "Software Engineer"},
      "expected_status": 400,
      "description": "Create a new employee with invalid email"
    },
    {
      "name": "Create new employee with duplicate email",
      "method": "POST",
      "path": "/employees",
      "payload": {"firstName": "John", "lastName": "Doe", "email": "john.doe@example.com", "jobTitle": "Software Engineer"},
      "expected_status": 409,
      "description": "Create a new employee with duplicate email",
      "context_required": {"type": "employee", "fields": ["email"]}
    }
  ],
  "boundary": [
    {
      "name": "Create new employee with very long first name",
      "method": "POST",
      "path": "/employees",
      "payload": {"firstName": "a".repeat(100), "lastName": "Doe", "email": "john.doe@example.com", "jobTitle": "Software Engineer"},
      "expected_status": 201,
      "description": "Create a new employee with very long first name",
      "context_capture": {"enabled": true, "fields": ["id", "firstName", "lastName"], "store_as": "employee"}
    },
    {
      "name": "Create new employee with empty job title",
      "method": "POST",
      "path": "/employees",
      "payload": {"firstName": "John", "lastName": "Doe", "email": "john.doe@example.com", "jobTitle": ""},
      "expected_status": 201,
      "description": "Create a new employee with empty job title",
      "context_capture": {"enabled": true, "fields": ["id", "firstName", "lastName"], "store_as": "employee"}
    }
  ]
}

/employees/{id} PUT.raw_response:
{
  "positive": [
    {
      "name": "Update existing employee",
      "method": "PUT",
      "path": "/employees/{id}",
      "path_params": {"id": "{{CONTEXT:resource.id}}"},
      "payload": {"firstName": "John", "lastName": "Doe", "email": "john.doe@example.com"},
      "expected_status": 200,
      "description": "Update existing employee",
      "context_required": {"type": "resource", "fields": ["id"]},
      "context_capture": {"enabled": true, "fields": ["id", "firstName", "lastName", "email"], "store_as": "resource"}
    },
    {
      "name": "Update employee with new job title",
      "method": "PUT",
      "path": "/employees/{id}",
      "path_params": {"id": "{{CONTEXT:resource.id}}"},
      "payload": {"jobTitle": "Senior Software Engineer", "department": "IT"},
      "expected_status": 200,
      "description": "Update employee job title",
      "context_required": {"type": "resource", "fields": ["id"]},
      "context_capture": {"enabled": true, "fields": ["id", "jobTitle", "department"], "store_as": "resource"}
    },
    {
      "name": "Update employee with new phone number",
      "method": "PUT",
      "path": "/employees/{id}",
      "path_params": {"id": "{{CONTEXT:resource.id}}"},
      "payload": {"phoneNumber": "+1 123 456 7890"},
      "expected_status": 200,
      "description": "Update employee phone number",
      "context_required": {"type": "resource", "fields": ["id"]},
      "context_capture": {"enabled": true, "fields": ["id", "phoneNumber"], "store_as": "resource"}
    }
  ],
  "negative": [
    {
      "name": "Update non-existent employee",
      "method": "PUT",
      "path": "/employees/{id}",
      "path_params": {"id": "99999"},
      "payload": {"firstName": "Jane", "lastName": "Doe"},
      "expected_status": 404,
      "description": "Update non-existent employee"
    },
    {
      "name": "Update employee with invalid email",
      "method": "PUT",
      "path": "/employees/{id}",
      "path_params": {"id": "{{CONTEXT:resource.id}}"},
      "payload": {"email": "invalid_email"},
      "expected_status": 400,
      "description": "Update employee with invalid email",
      "context_required": {"type": "resource", "fields": ["id"]}
    },
    {
      "name": "Update employee with empty payload",
      "method": "PUT",
      "path": "/employees/{id}",
      "path_params": {"id": "{{CONTEXT:resource.id}}"},
      "payload": {},
      "expected_status": 400,
      "description": "Update employee with empty payload",
      "context_required": {"type": "resource", "fields": ["id"]}
    }
  ],
  "boundary": [
    {
      "name": "Update employee with maximum length first name",
      "method": "PUT",
      "path": "/employees/{id}",
      "path_params": {"id": "{{CONTEXT:resource.id}}"},
      "payload": {"firstName": "a".repeat(50)},
      "expected_status": 200,
      "description": "Update employee with maximum length first name",
      "context_required": {"type": "resource", "fields": ["id"]},
      "context_capture": {"enabled": true, "fields": ["id", "firstName"], "store_as": "resource"}
    },
    {
      "name": "Update employee with minimum length last name",
      "method": "PUT",
      "path": "/employees/{id}",
      "path_params": {"id": "{{CONTEXT:resource.id}}"},
      "payload": {"lastName": "a"},
      "expected_status": 200,
      "description": "Update employee with minimum length last name",
      "context_required": {"type": "resource", "fields": ["id"]},
      "context_capture": {"enabled": true, "fields": ["id", "lastName"], "store_as": "resource"}
    }
  ]
}
